// Parse Phantom Buster output — handles both single prospect and array
const input = $input.first().json;
const prospects = Array.isArray(input.prospects) ? input.prospects : (Array.isArray(input) ? input : [input]);

return prospects.map(p => ({
  json: {
    fullName: p.fullName || p.name || `${p.firstName || ''} ${p.lastName || ''}`.trim(),
    firstName: p.firstName || p.fullName?.split(' ')[0] || '',
    lastName: p.lastName || p.fullName?.split(' ').slice(1).join(' ') || '',
    title: p.title || p.headline || '',
    company: p.company || p.companyName || '',
    location: p.location || '',
    linkedinUrl: p.linkedinUrl || p.profileUrl || p.url || '',
    connectionDegree: p.connectionDegree || p.degree || '',
    summary: p.summary || p.description || '',
    industry: p.industry || '',
    companySize: p.companySize || p.employeeCount || '',
    mutualConnections: p.mutualConnections || p.sharedConnections || 0
  }
}));

// Parse Claude's response and combine with original prospect data
const claudeResponse = $input.first().json;
const prospectData = $('Parse Prospect Data').first().json;

let scoring;
try {
  const content = claudeResponse.content[0].text;
  // Handle case where Claude wraps JSON in markdown code blocks
  const jsonStr = content.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  scoring = JSON.parse(jsonStr);
} catch (e) {
  scoring = {
    icp_fit_score: 0,
    fit_rationale: 'Failed to parse Claude response: ' + e.message,
    role_relevance: 'unknown',
    decision_authority: 'unknown',
    recommended_approach: 'skip',
    connection_notes: '',
    hubspot_tags: ['parse_error']
  };
}

return [{
  json: {
    ...prospectData,
    ...scoring
  }
}];

// Log skipped prospects
const prospect = $input.first().json;
return [{ json: { status: 'skipped', reason: `ICP score ${prospect.icp_fit_score} < 6`, prospect: prospect.fullName, company: prospect.company, score: prospect.icp_fit_score } }];
